// // This comment suggests that the circuit is sensitive to high values of A1 and low values of A2, but in reality, it operates on the opposite condition.
module top_module(
    Y   ,
    A1  ,
    A2  ,
    B1_N
);output Y   ;
    input  A1  ;
    input  A2  ;
    input  B1_N;

    // Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNB ;

    assign Y = (A1 & !A2) | !B1_N;

endmodule
